import { createContext, useContext, useEffect, useState, ReactNode, useRef } from 'react';
import { Session, User, AuthError } from '@supabase/supabase-js';
import { supabase, User as AppUser } from '@/integrations/supabase/client';

// Extended user type with company info
export interface AuthUser extends Omit<AppUser, 'password_hash'> {
    id: string;
    email: string;
    first_name: string | null;
    last_name: string | null;
    company_id: string | null;
    role: 'super_admin' | 'company_admin' | 'operador' | null;
    is_active: boolean | null;
    company?: {
        id: string;
        name: string;
        slug: string;
        subscription_plan: 'free' | 'starter' | 'professional' | 'enterprise' | null;
        status: 'active' | 'suspended' | 'trial' | 'cancelled' | null;
    } | null;
}

interface AuthContextType {
    user: AuthUser | null;
    session: Session | null;
    loading: boolean;
    signIn: (email: string, password: string) => Promise<{ error: AuthError | null }>;
    signUp: (email: string, password: string, metadata?: SignUpMetadata) => Promise<{ error: AuthError | null }>;
    signOut: () => Promise<void>;
    refreshUser: () => Promise<void>;
}

interface SignUpMetadata {
    first_name?: string;
    last_name?: string;
    company_name?: string;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
    const [user, setUser] = useState<AuthUser | null>(null);
    const [session, setSession] = useState<Session | null>(null);
    const [loading, setLoading] = useState(true);
    const fetchingProfileFor = useRef<string | null>(null);

    // Fetch extended user profile with company info (with timeout)
    const fetchUserProfile = async (authUserId: string): Promise<AuthUser | null> => {
        const start = Date.now();
        // Prevent concurrent fetches for the same user
        if (fetchingProfileFor.current === authUserId) {
            console.log(`[Auth] Fetch already in progress for ${authUserId}, skipping.`);
            return null;
        }

        fetchingProfileFor.current = authUserId;
        console.log(`[Auth] Starting profile fetch for ${authUserId}`);

        const timeoutPromise = new Promise<null>((resolve) => {
            setTimeout(() => {
                const elapsed = Date.now() - start;
                console.warn(`[Auth] Profile fetch TIMEOUT after ${elapsed}ms`);
                fetchingProfileFor.current = null;
                resolve(null);
            }, 10000); // 10s is enough for any DB query
        });

        const fetchPromise = async (): Promise<AuthUser | null> => {
            try {
                const t0 = Date.now();
                const { data, error } = await supabase
                    .from('users')
                    .select('*')
                    .eq('id', authUserId)
                    .maybeSingle();

                console.log(`[Auth] Users table query took ${Date.now() - t0}ms`);

                if (error) {
                    console.error('[Auth] Error fetching users table:', error);
                    return null;
                }

                if (!data) {
                    console.warn('[Auth] User not found in public.users table');
                    return null;
                }

                const { password_hash, ...userWithoutPassword } = data;

                let company = null;
                if (userWithoutPassword.company_id) {
                    const t1 = Date.now();
                    const { data: companyData, error: companyError } = await supabase
                        .from('companies')
                        .select('id, name, slug, subscription_plan, status')
                        .eq('id', userWithoutPassword.company_id)
                        .maybeSingle();

                    console.log(`[Auth] Companies table query took ${Date.now() - t1}ms`);
                    if (companyError) console.error('[Auth] Companies fetch error:', companyError);
                    company = companyData;
                }

                console.log(`[Auth] Total profile fetch success in ${Date.now() - start}ms`);
                return { ...userWithoutPassword, company } as AuthUser;
            } catch (err) {
                console.error('[Auth] Exception in fetchUserProfile:', err);
                return null;
            } finally {
                fetchingProfileFor.current = null;
            }
        };

        return Promise.race([fetchPromise(), timeoutPromise]);
    };

    // Refresh user data
    const refreshUser = async () => {
        if (session?.user?.id) {
            const userProfile = await fetchUserProfile(session.user.id);
            setUser(userProfile);
        }
    };

    // Initialize auth state and listen for session changes
    useEffect(() => {
        let mounted = true;
        let initialLoadDone = false;

        const initAuth = async () => {
            try {
                console.log('[Auth] Starting initial session recovery...');
                const { data: { session: initialSession } } = await supabase.auth.getSession();

                if (!mounted) return;
                setSession(initialSession);

                if (initialSession?.user?.id) {
                    const profile = await fetchUserProfile(initialSession.user.id);
                    if (profile && mounted) {
                        setUser(profile);
                    }
                }
            } catch (err) {
                console.error('[Auth] Error during auth initialization:', err);
            } finally {
                if (mounted) {
                    setLoading(false);
                    initialLoadDone = true;
                    console.log('[Auth] Initial auth load complete.');
                }
            }
        };

        const { data: { subscription } } = supabase.auth.onAuthStateChange(
            async (event, newSession) => {
                // Skip processing if initial load is still in progress 
                // to avoid double fetching profiles
                if (!initialLoadDone && (event === 'INITIAL_SESSION' || event === 'SIGNED_IN')) {
                    console.log(`[Auth] Listener skipping ${event} during init phase.`);
                    return;
                }

                console.log(`[Auth] Event: ${event}`);

                if (!mounted) return;
                setSession(newSession);

                if (event === 'SIGNED_OUT') {
                    setUser(null);
                    setLoading(false);
                    return;
                }

                // If user changed or we don't have a profile yet
                if (newSession?.user?.id && (!user || user.id !== newSession.user.id)) {
                    const profile = await fetchUserProfile(newSession.user.id);
                    if (profile && mounted) {
                        setUser(profile);
                    }
                    if (mounted) setLoading(false);
                }
            }
        );

        initAuth();

        return () => {
            mounted = false;
            subscription.unsubscribe();
        };
    }, []);

    // Sign in with email and password
    const signIn = async (email: string, password: string) => {
        const { error } = await supabase.auth.signInWithPassword({
            email,
            password,
        });
        return { error };
    };

    // Sign up with email and password
    const signUp = async (email: string, password: string, metadata?: SignUpMetadata) => {
        const { error } = await supabase.auth.signUp({
            email,
            password,
            options: {
                data: metadata,
            },
        });
        return { error };
    };

    // Sign out
    const signOut = async () => {
        await supabase.auth.signOut();
        setUser(null);
        setSession(null);
    };

    const value: AuthContextType = {
        user,
        session,
        loading,
        signIn,
        signUp,
        signOut,
        refreshUser,
    };

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
}

// Helper hooks for role-based access
export function useIsSuperAdmin() {
    const { user } = useAuth();
    return user?.role === 'super_admin';
}

export function useIsCompanyAdmin() {
    const { user } = useAuth();
    return user?.role === 'company_admin' || user?.role === 'super_admin';
}

export function useCompanyId() {
    const { user } = useAuth();
    return user?.company_id;
}

export function useHasActiveSubscription() {
    const { user } = useAuth();
    if (!user?.company) return false;
    return user.company.status === 'active' || user.company.status === 'trial';
}

import * as React from "react";

const MOBILE_BREAKPOINT = 768;

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined);

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    };
    mql.addEventListener("change", onChange);
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    return () => mql.removeEventListener("change", onChange);
  }, []);

  return !!isMobile;
}

import * as React from "react";

import type { ToastActionElement, ToastProps } from "@/components/ui/toast";

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 1000000;

type ToasterToast = ToastProps & {
  id: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: ToastActionElement;
};

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type ActionType = typeof actionTypes;

type Action =
  | {
      type: ActionType["ADD_TOAST"];
      toast: ToasterToast;
    }
  | {
      type: ActionType["UPDATE_TOAST"];
      toast: Partial<ToasterToast>;
    }
  | {
      type: ActionType["DISMISS_TOAST"];
      toastId?: ToasterToast["id"];
    }
  | {
      type: ActionType["REMOVE_TOAST"];
      toastId?: ToasterToast["id"];
    };

interface State {
  toasts: ToasterToast[];
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>();

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return;
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId);
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    });
  }, TOAST_REMOVE_DELAY);

  toastTimeouts.set(toastId, timeout);
};

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) => (t.id === action.toast.id ? { ...t, ...action.toast } : t)),
      };

    case "DISMISS_TOAST": {
      const { toastId } = action;

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId);
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id);
        });
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t,
        ),
      };
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        };
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      };
  }
};

const listeners: Array<(state: State) => void> = [];

let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach((listener) => {
    listener(memoryState);
  });
}

type Toast = Omit<ToasterToast, "id">;

function toast({ ...props }: Toast) {
  const id = genId();

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    });
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id });

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss();
      },
    },
  });

  return {
    id: id,
    dismiss,
    update,
  };
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState);

  React.useEffect(() => {
    listeners.push(setState);
    return () => {
      const index = listeners.indexOf(setState);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    };
  }, [state]);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  };
}

export { useToast, toast };

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface AccountHealth {
    activeCampaigns: number;
    maxCampaigns: number;
    activeIntegrations: number;
    maxIntegrations: number;
    lastSyncAt: string | null;
    integrationStatus: 'connected' | 'expired' | 'error' | 'not_connected';
    alerts: Array<{
        type: 'warning' | 'error' | 'info';
        message: string;
    }>;
}

export function useAccountHealth() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['account-health', companyId],
        queryFn: async (): Promise<AccountHealth> => {
            if (!companyId) throw new Error('No company ID');

            // Get company limits
            const { data: company, error: companyError } = await supabase
                .from('companies')
                .select('max_campaigns, max_integrations')
                .eq('id', companyId)
                .single();

            if (companyError) throw companyError;

            // Get active campaigns count
            const { count: activeCampaigns } = await supabase
                .from('campaigns')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId)
                .eq('status', 'active');

            // Get integrations
            const { data: integrations } = await supabase
                .from('integrations')
                .select('status, last_sync_at, token_expires_at')
                .eq('company_id', companyId)
                .eq('platform', 'meta');

            const activeIntegrations = integrations?.filter(i => i.status === 'active').length || 0;
            const latestSync = integrations?.map(i => i.last_sync_at).filter(Boolean).sort().reverse()[0] || null;

            // Determine integration status
            let integrationStatus: AccountHealth['integrationStatus'] = 'not_connected';
            if (integrations && integrations.length > 0) {
                const hasExpired = integrations.some(i =>
                    i.token_expires_at && new Date(i.token_expires_at) < new Date()
                );
                const hasError = integrations.some(i => i.status === 'error');

                if (hasExpired) {
                    integrationStatus = 'expired';
                } else if (hasError) {
                    integrationStatus = 'error';
                } else if (activeIntegrations > 0) {
                    integrationStatus = 'connected';
                }
            }

            // Generate alerts
            const alerts: AccountHealth['alerts'] = [];

            if (integrationStatus === 'expired') {
                alerts.push({ type: 'warning', message: 'Token do Meta expirado. Reconecte sua conta.' });
            }

            if (integrationStatus === 'not_connected') {
                alerts.push({ type: 'info', message: 'Conecte sua conta do Meta para começar.' });
            }

            if (activeCampaigns && company?.max_campaigns && activeCampaigns >= company.max_campaigns * 0.9) {
                alerts.push({ type: 'warning', message: `Você está próximo do limite de campanhas (${activeCampaigns}/${company.max_campaigns}).` });
            }

            return {
                activeCampaigns: activeCampaigns || 0,
                maxCampaigns: company?.max_campaigns || 10,
                activeIntegrations,
                maxIntegrations: company?.max_integrations || 2,
                lastSyncAt: latestSync,
                integrationStatus,
                alerts,
            };
        },
        enabled: !!companyId,
        staleTime: 2 * 60 * 1000,
    });
}

export function useSyncStatus() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['sync-status', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('sync_history')
                .select('*')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(5);

            if (error) throw error;
            return data || [];
        },
        enabled: !!companyId,
        staleTime: 1 * 60 * 1000,
    });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

export interface Audit {
    id: string;
    company_id: string;
    creative_id: string;
    policy_id: string | null;
    status: string | null;
    compliance_score: number | null;
    performance_score: number | null;
    issues: AuditIssue[] | null;
    recommendations: string[] | null;
    ai_analysis: AiAnalysis | null;
    created_at: string;
    // Joined data
    creatives?: {
        name: string;
        image_url: string | null;
        type: string | null;
    };
    policies?: {
        name: string;
    };
}

export interface AuditIssue {
    type: 'keyword' | 'text_length' | 'brand' | 'performance';
    severity: 'error' | 'warning' | 'info';
    message: string;
    details?: Record<string, unknown>;
}

export interface AiAnalysis {
    quality_score?: number;
    tone_analysis?: string;
    strengths?: string[];
    weaknesses?: string[];
    suggestions?: string[];
}

export function useAudits() {
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const companyId = user?.company?.id;

    const auditsQuery = useQuery({
        queryKey: ['audits', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('audits')
                .select(`
          *,
          creatives(name, image_url, type),
          policies(name)
        `)
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(100);

            if (error) throw error;
            return data as unknown as Audit[];
        },
        enabled: !!companyId,
    });

    const runAudit = useMutation({
        mutationFn: async ({ creativeId, policyId }: { creativeId: string; policyId?: string }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/audit-creative`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        creative_id: creativeId,
                        policy_id: policyId,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Audit failed');
            }

            return response.json();
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['audits', companyId] });
            toast.success('Auditoria concluída');
        },
        onError: (error) => {
            toast.error(`Erro na auditoria: ${error.message}`);
        },
    });

    const runBatchAudit = useMutation({
        mutationFn: async ({ campaignId, policyId, limit }: { campaignId?: string; policyId?: string; limit?: number }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/audit-batch`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        campaign_id: campaignId,
                        policy_id: policyId,
                        limit,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Batch audit failed');
            }

            return response.json();
        },
        onSuccess: (data) => {
            queryClient.invalidateQueries({ queryKey: ['audits', companyId] });
            toast.success(`Auditoria em lote concluída: ${data.audited} criativos`);
        },
        onError: (error) => {
            toast.error(`Erro na auditoria em lote: ${error.message}`);
        },
    });

    return {
        audits: auditsQuery.data || [],
        isLoading: auditsQuery.isLoading,
        error: auditsQuery.error,
        runAudit,
        runBatchAudit,
    };
}

export function useAuditsCount() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['audits-count', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { count: total, error: totalError } = await supabase
                .from('audits')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId);

            if (totalError) throw totalError;

            const { count: pending, error: pendingError } = await supabase
                .from('audits')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId)
                .eq('status', 'pending');

            if (pendingError) throw pendingError;

            return {
                total: total || 0,
                pending: pending || 0
            };
