                                                    Exportar PDF <Zap className="ml-2 w-4 h-4 group-hover:animate-bounce" />
                                                </Button>
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {/* Problems & Recommendations List */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <div className="space-y-6">
                                        <h4 className="text-sm font-black text-ch-white uppercase tracking-[.2rem] flex items-center gap-3">
                                            <div className="w-1.5 h-5 bg-rose-500 rounded-full" /> Pontos de Correção
                                        </h4>
                                        <div className="space-y-3">
                                            {(selectedAudit.issues && selectedAudit.issues.length > 0) ? (
                                                selectedAudit.issues.map((issue: AuditIssue, i: number) => (
                                                    <div key={i} className="flex items-start gap-4 p-5 bg-white/[0.02] border border-white/5 rounded-2xl hover:border-white/10 transition-all group">
                                                        <div className="mt-1">{getIssueSeverityIcon(issue.severity)}</div>
                                                        <div>
                                                            <p className="text-[11px] font-black text-ch-white uppercase mb-1 group-hover:text-ch-orange transition-colors">{issue.message}</p>
                                                            <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest">{issue.type}</p>
                                                        </div>
                                                    </div>
                                                ))
                                            ) : (
                                                <div className="p-8 text-center bg-emerald-500/5 border border-emerald-500/10 rounded-2xl">
                                                    <CheckCircle className="w-8 h-8 text-emerald-500 mx-auto mb-3 opacity-30" />
                                                    <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Nenhuma Irregularidade Detectada</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    <div className="space-y-6">
                                        <h4 className="text-sm font-black text-ch-white uppercase tracking-[.2rem] flex items-center gap-3">
                                            <div className="w-1.5 h-5 bg-ch-orange rounded-full" /> Recomendações de Performance
                                        </h4>
                                        <div className="space-y-3">
                                            {(selectedAudit.recommendations && selectedAudit.recommendations.length > 0) ? (
                                                selectedAudit.recommendations.map((rec, i) => (
                                                    <div key={i} className="flex items-start gap-4 p-5 bg-white/[0.02] border border-white/5 rounded-2xl hover:border-white/10 transition-all group">
                                                        <div className="w-6 h-6 bg-ch-orange/10 rounded-lg flex items-center justify-center flex-shrink-0 mt-1">
                                                            <Zap className="w-3.5 h-3.5 text-ch-orange" />
                                                        </div>
                                                        <p className="text-[11px] font-black text-ch-text-muted uppercase group-hover:text-ch-white transition-colors">{rec}</p>
                                                    </div>
                                                ))
                                            ) : (
                                                <div className="p-8 text-center bg-white/[0.02] border border-white/5 rounded-2xl opacity-40">
                                                    <Activity className="w-8 h-8 text-ch-text-muted mx-auto mb-3" />
                                                    <p className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">Aguardando Dados de Tração</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                {/* Detail Bottom Actions */}
                                <div className="flex flex-col md:flex-row gap-4 pt-6 border-t border-white/5">
                                    <Button
                                        onClick={() => navigate(`/criativos/${selectedAudit.creative_id}`)}
                                        className="flex-1 bg-ch-dark-gray/40 hover:bg-white/5 text-ch-white border-white/5 h-16 rounded-2xl font-black uppercase text-[11px] tracking-widest transition-all"
                                    >
                                        <Eye className="w-5 h-5 mr-3 text-ch-orange" />
                                        Inspecionar Ativo Visual
                                    </Button>
                                    <Button
                                        variant="outline"
                                        className="flex-1 bg-transparent border-white/5 hover:bg-white/5 hover:text-ch-orange h-16 rounded-2xl font-black uppercase text-[11px] tracking-widest transition-all"
                                    >
                                        <Briefcase className="w-5 h-5 mr-3" />
                                        Atribuir Tarefa de Ajuste
                                    </Button>
                                </div>
                            </div>
                        </DialogContent>
                    </Dialog>
                )}
            </AnimatePresence>
        </motion.div>
    );
}

import { useState } from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import {
    CreditCard,
    Check,
    Loader2,
    Zap,
    Crown,
    Building2,
    Users,
    Megaphone,
    FileCheck,
    Sparkles,
    ExternalLink
} from 'lucide-react';
import { toast } from 'sonner';

interface Plan {
    id: string;
    name: string;
    price: number;
    features: string[];
    limits: {
        campaigns: number;
        creatives: number;
        users: number;
        ai_requests: number;
    };
    popular?: boolean;
}

const PLANS: Plan[] = [
    {
        id: 'starter',
        name: 'Starter',
        price: 97,
        features: [
            'Até 5 campanhas',
            'Até 50 criativos',
            'Até 2 usuários',
            '100 requisições IA/mês',
            'Relatórios básicos',
        ],
        limits: { campaigns: 5, creatives: 50, users: 2, ai_requests: 100 },
    },
    {
        id: 'pro',
        name: 'Pro',
        price: 297,
        features: [
            'Até 20 campanhas',
            'Até 200 criativos',
            'Até 5 usuários',
            '500 requisições IA/mês',
            'Relatórios avançados',
            'Automações',
            'Suporte prioritário',
        ],
        limits: { campaigns: 20, creatives: 200, users: 5, ai_requests: 500 },
        popular: true,
    },
    {
        id: 'enterprise',
        name: 'Enterprise',
        price: 597,
        features: [
            'Campanhas ilimitadas',
            'Criativos ilimitados',
            'Usuários ilimitados',
            'Requisições IA ilimitadas',
            'Relatórios personalizados',
            'API access',
            'Onboarding dedicado',
            'SLA garantido',
        ],
        limits: { campaigns: -1, creatives: -1, users: -1, ai_requests: -1 },
    },
];

export default function Billing() {
    const { user } = useAuth();
    const companyId = user?.company?.id;
    const [selectedPlan, setSelectedPlan] = useState<string | null>(null);

    const { data: currentPlan } = useQuery({
        queryKey: ['current-plan', companyId],
        queryFn: async () => {
            if (!companyId) return null;
            const { data, error } = await supabase
                .from('companies')
                .select('plan, plan_expires_at')
                .eq('id', companyId)
                .single();
            if (error) throw error;
            return data;
        },
        enabled: !!companyId,
    });

    const subscribeToPlan = useMutation({
        mutationFn: async (planId: string) => {
            // In real implementation, this would redirect to Stripe Checkout
            // For now, we'll simulate the upgrade
            const { error } = await supabase
                .from('companies')
                .update({
                    plan: planId,
                    plan_expires_at: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
                })
                .eq('id', companyId);
            if (error) throw error;
            return planId;
        },
        onSuccess: (planId) => {
            toast.success(`Plano ${PLANS.find(p => p.id === planId)?.name} ativado!`);
        },
        onError: (error) => {
            toast.error(`Erro ao atualizar plano: ${error.message}`);
        },
    });

    const handleSubscribe = (planId: string) => {
        setSelectedPlan(planId);
        subscribeToPlan.mutate(planId);
    };

    const getFeatureIcon = (feature: string) => {
        if (feature.includes('campanha')) return Megaphone;
        if (feature.includes('criativo')) return Megaphone;
        if (feature.includes('usuário')) return Users;
        if (feature.includes('IA')) return Sparkles;
        if (feature.includes('Relatório')) return FileCheck;
        return Check;
    };

    return (
        <div className="p-8 max-w-6xl mx-auto">
            <div className="mb-8">
                <h1 className="text-2xl font-bold text-ch-white mb-2">Planos e Faturamento</h1>
                <p className="text-ch-text-muted">
                    Escolha o plano ideal para o seu negócio.
                </p>
            </div>

            {/* Current Plan */}
            {currentPlan?.plan && (
                <div className="glass rounded-xl p-6 mb-8">
                    <div className="flex items-center gap-4">
                        <div className="p-3 bg-ch-orange/20 rounded-lg">
                            <Crown className="w-6 h-6 text-ch-orange" />
                        </div>
                        <div>
                            <p className="text-ch-text-muted text-sm">Plano Atual</p>
                            <p className="text-xl font-bold text-ch-white capitalize">{currentPlan.plan}</p>
                        </div>
                    </div>
                </div>
            )}

            {/* Plans */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {PLANS.map((plan) => {
                    const isCurrentPlan = currentPlan?.plan === plan.id;

                    return (
                        <div
                            key={plan.id}
                            className={`glass rounded-xl p-6 relative ${plan.popular ? 'ring-2 ring-ch-orange' : ''
                                }`}
                        >
                            {plan.popular && (
                                <div className="absolute -top-3 left-1/2 -translate-x-1/2">
                                    <span className="px-3 py-1 bg-ch-orange text-white text-xs font-medium rounded-full">
                                        Mais Popular
                                    </span>
                                </div>
                            )}

                            <div className="mb-6">
                                <h3 className="text-xl font-bold text-ch-white">{plan.name}</h3>
                                <div className="mt-2">
                                    <span className="text-3xl font-bold text-ch-white">R$ {plan.price}</span>
                                    <span className="text-ch-text-muted">/mês</span>
                                </div>
                            </div>

                            <ul className="space-y-3 mb-6">
                                {plan.features.map((feature, idx) => {
                                    const Icon = getFeatureIcon(feature);
                                    return (
                                        <li key={idx} className="flex items-center gap-2 text-sm text-ch-text-muted">
                                            <Icon className="w-4 h-4 text-green-500 flex-shrink-0" />
                                            {feature}
                                        </li>
                                    );
                                })}
                            </ul>

                            <Button
                                onClick={() => handleSubscribe(plan.id)}
                                disabled={isCurrentPlan || subscribeToPlan.isPending}
                                className={`w-full ${plan.popular
                                        ? 'bg-ch-orange hover:bg-ch-orange/90'
                                        : 'bg-ch-dark-gray hover:bg-ch-gray border border-ch-dark-gray'
                                    }`}
                            >
                                {subscribeToPlan.isPending && selectedPlan === plan.id ? (
                                    <Loader2 className="w-4 h-4 animate-spin mr-2" />
                                ) : null}
                                {isCurrentPlan ? 'Plano Atual' : 'Assinar'}
                            </Button>
                        </div>
                    );
                })}
            </div>

            {/* FAQ */}
            <div className="mt-12 glass rounded-xl p-6">
                <h3 className="text-lg font-semibold text-ch-white mb-4">Perguntas Frequentes</h3>
                <div className="space-y-4">
                    <div>
                        <p className="font-medium text-ch-white">Como funciona o pagamento?</p>
                        <p className="text-sm text-ch-text-muted mt-1">
                            O pagamento é feito mensalmente via cartão de crédito. Você pode cancelar a qualquer momento.
                        </p>
                    </div>
                    <div>
                        <p className="font-medium text-ch-white">Posso mudar de plano?</p>
                        <p className="text-sm text-ch-text-muted mt-1">
                            Sim, você pode fazer upgrade ou downgrade a qualquer momento. A diferença será calculada proporcionalmente.
                        </p>
                    </div>
                    <div>
                        <p className="font-medium text-ch-white">O que acontece se eu exceder os limites?</p>
                        <p className="text-sm text-ch-text-muted mt-1">
                            Você receberá uma notificação e poderá fazer upgrade do plano para continuar usando.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
}

