    Play,
    Pause,
    Loader2,
    TrendingUp,
    TrendingDown,
    DollarSign,
    Eye,
    MousePointerClick,
    Target,
    Calendar,
    BarChart3,
    MoreVertical,
    Copy,
    Edit3,
    Trash2,
