const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
    }).format(value);
};

const formatNumber = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(2)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(2)}K`;
    return value.toLocaleString('pt-BR');
};

const formatPercent = (value: number) => {
    return `${value.toFixed(2)}%`;
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function CampanhaDetalhe() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const queryClient = useQueryClient();

    const [isRenameOpen, setIsRenameOpen] = useState(false);
    const [newName, setNewName] = useState('');
    const [isBudgetOpen, setIsBudgetOpen] = useState(false);
    const [newDailyBudget, setNewDailyBudget] = useState('');
    const [newLifetimeBudget, setNewLifetimeBudget] = useState('');

    const { data: campaign, isLoading } = useQuery({
        queryKey: ['campaign', id],
        queryFn: async () => {
            if (!id) throw new Error('No campaign ID');

            const { data, error } = await supabase
                .from('campaigns')
                .select('*, campaign_tags(tag:tags(*))')
                .eq('id', id)
                .single();

            if (error) throw error;
            return {
                ...(data as any),
                tags: (data as any).campaign_tags
            };
        },
        enabled: !!id,
    });

    const { data: adSets } = useQuery({
        queryKey: ['campaign-adsets', id],
        queryFn: async () => {
            if (!id) throw new Error('No campaign ID');

            const { data, error } = await supabase
                .from('ad_sets')
                .select('*')
                .eq('campaign_id', id)
                .order('spend', { ascending: false });

            if (error) throw error;
            return data || [];
        },
        enabled: !!id,
    });

    const { data: creatives } = useQuery({
        queryKey: ['campaign-creatives', id],
        queryFn: async () => {
            if (!id) throw new Error('No campaign ID');

            const { data, error } = await supabase
                .from('creatives')
                .select('*')
                .eq('campaign_id', id)
                .order('impressions', { ascending: false })
                .limit(6);

            if (error) throw error;
            return data || [];
        },
        enabled: !!id,
    });

    const campaignAction = useMutation({
        mutationFn: async ({ action, payload }: { action: string, payload?: any }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/meta-campaign-action`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    campaign_id: id,
                    action,
                    payload
                }),
            });

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Failed to perform action');
            }

            return response.json();
        },
        onSuccess: (data, variables) => {
            toast.success(`Ação ${variables.action} realizada com sucesso`);
            queryClient.invalidateQueries({ queryKey: ['campaign', id] });
            setIsRenameOpen(false);
            setIsBudgetOpen(false);
        },
        onError: (error) => {
            toast.error(`Erro: ${error.message}`);
        }
    });

    const handleRename = () => {
        if (!newName) return;
        campaignAction.mutate({ action: 'rename', payload: { name: newName } });
    };

    const handleUpdateBudget = () => {
        const payload: any = {};
        if (newDailyBudget) payload.daily_budget = parseFloat(newDailyBudget.replace(',', '.')) * 100;
        if (newLifetimeBudget) payload.lifetime_budget = parseFloat(newLifetimeBudget.replace(',', '.')) * 100;

        if (Object.keys(payload).length === 0) return;
        campaignAction.mutate({ action: 'update_budget', payload });
    };

    const handleDuplicate = () => {
        if (confirm('Tem certeza que deseja duplicar esta campanha?')) {
            campaignAction.mutate({ action: 'duplicate', payload: { name: `${campaign?.name} (Cópia)` } });
        }
    };

    const handleOpenRename = () => {
        setNewName(campaign?.name || '');
        setIsRenameOpen(true);
    };

    const handleOpenBudget = () => {
        setNewDailyBudget(campaign?.daily_budget ? (campaign.daily_budget).toString() : '');
        setNewLifetimeBudget(campaign?.lifetime_budget ? (campaign.lifetime_budget).toString() : '');
        setIsBudgetOpen(true);
    };

    const getStatusBadge = (status: string) => {
        const config: Record<string, { label: string, color: string, icon: any }> = {
            active: { label: 'Ativa', color: 'emerald-500', icon: Play },
            paused: { label: 'Pausada', color: 'amber-500', icon: Pause },
            deleted: { label: 'Removida', color: 'rose-500', icon: Trash2 },
            archived: { label: 'Arquivada', color: 'ch-text-dimmed', icon: Archive },
        };
        const cfg = config[status] || config.paused;
        const Icon = cfg.icon;
        return (
            <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-widest bg-${cfg.color}/10 text-${cfg.color} border border-${cfg.color}/20`}>
                <Icon className="w-3 h-3" />
                {cfg.label}
            </span>
        );
    };

    if (isLoading || !campaign) {
        return (
            <div className="p-6 flex flex-col items-center justify-center min-h-[500px] gap-4">
                <Loader2 className="w-10 h-10 animate-spin text-ch-orange opacity-40" />
                <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-widest">Carregando inteligência da campanha...</p>
            </div>
        );
    }

    const ctr = campaign.impressions > 0 ? (campaign.clicks / campaign.impressions) * 100 : 0;
    const cpc = campaign.clicks > 0 ? campaign.spend / campaign.clicks : 0;
    const cpm = campaign.impressions > 0 ? (campaign.spend / campaign.impressions) * 1000 : 0;

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            {/* Navigation & Actions */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-5">
                    <Button
                        variant="outline"
                        size="icon"
                        onClick={() => navigate('/campanhas')}
                        className="h-12 w-12 bg-ch-dark-gray/40 border-white/5 hover:bg-ch-orange/10 hover:text-ch-orange transition-all duration-300 rounded-2xl group"
                    >
                        <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                    </Button>
                    <div>
                        <div className="flex items-center gap-3 mb-1">
                            <Megaphone className="w-4 h-4 text-ch-orange" />
                            <span className="text-[10px] font-black text-ch-orange uppercase tracking-[0.2em]">Detalhes da Campanha</span>
                        </div>
                        <h1 className="text-3xl font-black text-ch-white tracking-tight uppercase italic">{campaign.name}</h1>
                        <div className="flex items-center gap-3 mt-1.5">
                            <span className="text-[11px] font-bold text-ch-text-dimmed">ID: {campaign.external_id}</span>
                            <span className="w-1 h-1 rounded-full bg-white/10" />
                            <span className="text-[11px] font-black text-ch-text-muted uppercase tracking-wider">{campaign.objective?.replace(/_/g, ' ')}</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <TagList tags={campaign.tags} />
                    <TagSelector
                        entityId={campaign.id}
                        entityType="campaign"
                        selectedTags={campaign.tags || []}
                    />
                    <div className="w-px h-8 bg-white/5 mx-2" />
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-xl transition-all h-12 px-6 shadow-xl group">
                                Gerenciar <Settings className="ml-2 h-4 w-4 group-hover:rotate-90 transition-transform" />
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="bg-ch-black-soft border-white/10 w-56">
                            <DropdownMenuLabel className="text-[10px] font-black uppercase tracking-widest text-ch-text-dimmed">Status & Controle</DropdownMenuLabel>
                            {campaign.status === 'active' ? (
                                <DropdownMenuItem onClick={() => campaignAction.mutate({ action: 'pause' })} className="py-3 cursor-pointer">
                                    <Pause className="mr-3 h-4 w-4 text-amber-500" /> <span className="font-bold">Pausar Campanha</span>
                                </DropdownMenuItem>
                            ) : (
                                <DropdownMenuItem onClick={() => campaignAction.mutate({ action: 'activate' })} className="py-3 cursor-pointer">
                                    <Play className="mr-3 h-4 w-4 text-emerald-500" /> <span className="font-bold">Ativar Campanha</span>
                                </DropdownMenuItem>
                            )}
                            <DropdownMenuSeparator className="bg-white/5" />
                            <DropdownMenuItem onClick={handleDuplicate} className="py-3 cursor-pointer">
                                <Copy className="mr-3 h-4 w-4 text-blue-400" /> Duplicar Estrutura
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={handleOpenRename} className="py-3 cursor-pointer">
                                <Edit3 className="mr-3 h-4 w-4 text-indigo-400" /> Alterar Nome
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={handleOpenBudget} className="py-3 cursor-pointer">
                                <DollarSign className="mr-3 h-4 w-4 text-teal-400" /> Ajustar Orçamento
                            </DropdownMenuItem>
                            <DropdownMenuSeparator className="bg-white/5" />
                            <DropdownMenuItem className="py-3 text-rose-500 opacity-50 cursor-not-allowed">
                                <Archive className="mr-3 h-4 w-4" /> Arquivar Definitivo
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>
                </div>
            </motion.div>

            {/* Status Row */}
            <motion.div variants={item} className="flex flex-wrap items-center gap-3">
                {getStatusBadge(campaign.status)}
                <div className="px-3 py-1 bg-white/[0.03] border border-white/5 rounded-full flex items-center gap-2">
                    <Calendar className="w-3.5 h-3.5 text-ch-text-dimmed" />
                    <span className="text-[10px] font-bold text-ch-text-muted uppercase">Criada em {format(new Date(campaign.created_at), "dd/MM/yyyy", { locale: ptBR })}</span>
                </div>
                <div className="px-3 py-1 bg-white/[0.03] border border-white/5 rounded-full flex items-center gap-2">
                    <Sparkles className="w-3.5 h-3.5 text-ch-orange" />
                    <span className="text-[10px] font-bold text-ch-text-muted uppercase italic">Escaneada por ClickHero IA</span>
                </div>
            </motion.div>

            {/* Analytics Grid */}
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
                {[
                    { label: 'Gasto Total', value: formatCurrency(campaign.spend || 0), icon: DollarSign, color: 'emerald-400' },
                    { label: 'Impressões', value: formatNumber(campaign.impressions || 0), icon: Eye, color: 'blue-400' },
                    { label: 'Cliques', value: formatNumber(campaign.clicks || 0), icon: MousePointerClick, color: 'indigo-400' },
                    { label: 'CTR Médio', value: formatPercent(ctr), icon: TrendingUp, color: 'ch-orange' },
                    { label: 'CPC Médio', value: formatCurrency(cpc), icon: Target, color: 'amber-400' },
                    { label: 'CPM Médio', value: formatCurrency(cpm), icon: BarChart3, color: 'teal-400' },
                ].map((metric) => (
                    <motion.div key={metric.label} variants={item} whileHover={{ y: -3 }} className="glass rounded-2xl p-5 border-white/5 shadow-lg group">
                        <div className="flex items-center gap-2 mb-3">
                            <metric.icon className={`w-4 h-4 text-${metric.color}`} />
                            <span className="text-[10px] font-black text-ch-text-muted uppercase tracking-wider">{metric.label}</span>
                        </div>
                        <p className="text-xl font-black text-ch-white tracking-tight tabular-nums group-hover:text-ch-orange transition-colors">{metric.value}</p>
                    </motion.div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Structure Content */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Budget & Limits */}
                    <motion.div variants={item} className="glass rounded-3xl p-8 border-white/5 relative overflow-hidden group shadow-2xl">
                        <div className="absolute top-0 right-0 p-12 opacity-[0.02] pointer-events-none group-hover:opacity-[0.05] transition-opacity">
                            <DollarSign className="w-48 h-48" />
                        </div>
                        <h3 className="text-lg font-black text-ch-white uppercase tracking-tight mb-8 flex items-center gap-2">
                            <div className="w-1.5 h-6 bg-ch-orange rounded-full" /> Configurações Financeiras
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                            <div>
                                <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-[0.2em] mb-2">Budget Diário</p>
                                <p className="text-2xl font-black text-ch-white tabular-nums">
                                    {campaign.daily_budget ? formatCurrency(campaign.daily_budget) : '-'}
                                </p>
                            </div>
                            <div>
                                <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-[0.2em] mb-2">Budget Lifetime</p>
                                <p className="text-2xl font-black text-ch-white tabular-nums">
                                    {campaign.lifetime_budget ? formatCurrency(campaign.lifetime_budget) : '-'}
                                </p>
                            </div>
                            <div>
                                <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-[0.2em] mb-2">Último Update</p>
                                <p className="text-sm font-bold text-ch-white">
                                    {format(new Date(campaign.updated_at), "dd 'de' MMMM", { locale: ptBR })}<br />
                                    <span className="text-ch-text-muted">às {format(new Date(campaign.updated_at), "HH:mm")}</span>
                                </p>
                            </div>
                        </div>
                    </motion.div>

                    {/* Ad Sets Hierarchy */}
                    {adSets && adSets.length > 0 && (
                        <motion.div variants={item} className="glass rounded-3xl overflow-hidden border-white/5 shadow-2xl">
                            <div className="p-6 border-b border-white/5 flex items-center justify-between bg-white/[0.01]">
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-ch-orange/10 rounded-xl">
                                        <BarChart3 className="w-5 h-5 text-ch-orange" />
                                    </div>
                                    <h2 className="text-lg font-black text-ch-white uppercase tracking-tight">Conjuntos de Anúncios ({adSets.length})</h2>
                                </div>
                            </div>
                            <div className="divide-y divide-white/5">
                                {adSets.map((adSet: any) => (
                                    <div key={adSet.id} className="p-6 flex flex-col md:flex-row md:items-center justify-between hover:bg-white/[0.02] transition-all group cursor-pointer" onClick={() => navigate(`/adsets/${adSet.id}`)}>
                                        <div className="flex items-center gap-5">
                                            <div className="w-12 h-12 bg-ch-black border border-white/10 rounded-2xl flex items-center justify-center group-hover:border-ch-orange/30 transition-all">
                                                <Target className="w-6 h-6 text-ch-text-dimmed group-hover:text-ch-orange" />
                                            </div>
                                            <div>
                                                <p className="font-black text-ch-white group-hover:text-ch-orange transition-colors uppercase tracking-tight">{adSet.name}</p>
                                                <p className="text-[10px] text-ch-text-muted font-bold mt-1 uppercase tracking-widest leading-loose max-w-sm line-clamp-1">{adSet.targeting_summary || 'Público Aberto / Segmentação Ampla'}</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-8 mt-5 md:mt-0">
                                            <div className="text-right">
                                                <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1">Impressões</p>
                                                <p className="text-sm font-black text-ch-white tabular-nums">{formatNumber(adSet.impressions || 0)}</p>
                                            </div>
                                            <div className="text-right">
                                                <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1">Gasto</p>
                                                <p className="text-sm font-black text-emerald-400 tabular-nums">{formatCurrency(adSet.spend || 0)}</p>
                                            </div>
                                            <ChevronRight className="w-5 h-5 text-ch-text-dimmed group-hover:text-ch-orange group-hover:translate-x-1 transition-all" />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </motion.div>
                    )}
                </div>

                {/* Sidebar Preview */}
                <div className="space-y-8">
                    {/* Creatives Preview */}
                    {creatives && creatives.length > 0 && (
                        <motion.div variants={item} className="glass rounded-3xl p-8 border-white/5 shadow-2xl">
                            <div className="flex items-center justify-between mb-8">
                                <h2 className="text-lg font-black text-ch-white uppercase tracking-tight">Criativos Ativos</h2>
                                <Button variant="ghost" onClick={() => navigate('/criativos')} className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted hover:text-ch-orange">
                                    Ver Todos
                                </Button>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                {creatives.map((creative: any) => (
                                    <div key={creative.id} className="aspect-square rounded-2xl bg-ch-dark-gray border border-white/5 overflow-hidden group relative cursor-pointer" onClick={() => navigate(`/criativos/${creative.id}`)}>
                                        {creative.image_url ? (
                                            <img
                                                src={creative.image_url}
                                                alt={creative.name}
                                                className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                                            />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center text-ch-text-dimmed bg-white/[0.02]">
                                                <Megaphone className="w-8 h-8 opacity-20" />
                                            </div>
                                        )}
                                        <div className="absolute inset-x-0 bottom-0 p-3 bg-gradient-to-t from-black/80 to-transparent opacity-0 group-hover:opacity-100 transition-opacity">
                                            <p className="text-[9px] font-black text-ch-white text-center uppercase tracking-tighter line-clamp-1">{creative.name}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </motion.div>
                    )}

                    {/* Quick Insight */}
                    <motion.div variants={item} className="glass rounded-3xl p-8 border-white/5 bg-ch-orange/[0.02] border-l-4 border-l-ch-orange">
                        <div className="flex items-center gap-3 mb-4">
                            <Sparkles className="w-5 h-5 text-ch-orange" />
                            <h3 className="font-black text-ch-white uppercase tracking-tight">Status IA</h3>
                        </div>
                        <p className="text-xs text-ch-text-muted font-medium leading-relaxed">
                            Esta campanha está sendo monitorada ativamente. {creatives?.length || 0} criativos estão sob análise de fadiga e conformidade em tempo real.
                        </p>
                    </motion.div>
                </div>
            </div>

            {/* Dialogs */}
            <AnimatePresence>
                {isRenameOpen && (
                    <Dialog open={isRenameOpen} onOpenChange={setIsRenameOpen}>
                        <DialogContent className="bg-ch-black-soft border-white/10 shadow-2xl rounded-3xl">
                            <DialogHeader>
                                <DialogTitle className="text-xl font-black text-ch-white uppercase tracking-tight">Renomear Campanha</DialogTitle>
                                <DialogDescription className="text-ch-text-dimmed font-medium">
                                    Esta alteração será refletida no painel do Click.Hero e no Meta Ads Manager.
                                </DialogDescription>
                            </DialogHeader>
                            <div className="py-6">
                                <Label className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted mb-3 block">Novo Nome Administrativo</Label>
                                <Input
                                    value={newName}
                                    onChange={(e) => setNewName(e.target.value)}
                                    className="bg-ch-dark-gray/40 border-white/10 text-ch-white h-12 focus:border-ch-orange/50 transition-colors uppercase font-bold text-xs"
                                    placeholder="Ex: [V4] PERFORMANCE_CONV_AGOSTO"
                                />
                            </div>
                            <DialogFooter className="gap-3">
                                <Button variant="outline" onClick={() => setIsRenameOpen(false)} className="rounded-xl font-bold uppercase text-[10px] tracking-widest h-12 border-white/5 hover:bg-white/5">Descartar</Button>
                                <Button onClick={handleRename} disabled={campaignAction.isPending} className="bg-ch-orange hover:bg-ch-orange-hover text-ch-black font-black uppercase text-[10px] tracking-widest px-8 rounded-xl h-12 shadow-xl shadow-ch-orange/20">
                                    {campaignAction.isPending ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Confirmar Alteração'}
                                </Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                )}

                {isBudgetOpen && (
                    <Dialog open={isBudgetOpen} onOpenChange={setIsBudgetOpen}>
                        <DialogContent className="bg-ch-black-soft border-white/10 shadow-2xl rounded-3xl">
                            <DialogHeader>
                                <DialogTitle className="text-xl font-black text-ch-white uppercase tracking-tight">Ajustar Orçamento</DialogTitle>
                                <DialogDescription className="text-ch-text-dimmed font-medium">
                                    Define o novo limite de gasto para esta campanha no Meta.
                                </DialogDescription>
                            </DialogHeader>
                            <div className="grid gap-6 py-6">
                                <div className="space-y-4">
                                    <Label htmlFor="daily" className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Orçamento Diário (R$)</Label>
                                    <div className="relative">
                                        <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-ch-text-dimmed" />
                                        <Input
                                            id="daily"
                                            value={newDailyBudget}
                                            onChange={(e) => setNewDailyBudget(e.target.value)}
                                            className="bg-ch-dark-gray/40 border-white/10 text-ch-white h-14 pl-12 font-black tabular-nums text-lg focus:border-emerald-500/50"
                                            placeholder="0,00"
                                        />
                                    </div>
                                </div>
                                <div className="space-y-4">
                                    <Label htmlFor="lifetime" className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Orçamento Vitalício (R$)</Label>
                                    <div className="relative">
                                        <Copy className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-ch-text-dimmed" />
                                        <Input
                                            id="lifetime"
                                            value={newLifetimeBudget}
                                            onChange={(e) => setNewLifetimeBudget(e.target.value)}
                                            className="bg-ch-dark-gray/40 border-white/10 text-ch-white h-14 pl-12 font-black tabular-nums text-lg focus:border-blue-500/50"
                                            placeholder="Desabilitado"
                                        />
                                    </div>
                                </div>
                            </div>
                            <DialogFooter className="gap-3">
                                <Button variant="outline" onClick={() => setIsBudgetOpen(false)} className="rounded-xl font-bold uppercase text-[10px] tracking-widest h-12 border-white/5 hover:bg-white/5">Cancelar</Button>
                                <Button onClick={handleUpdateBudget} disabled={campaignAction.isPending} className="bg-ch-orange hover:bg-ch-orange-hover text-ch-black font-black uppercase text-[10px] tracking-widest px-8 rounded-xl h-12 shadow-xl shadow-ch-orange/20">
                                    {campaignAction.isPending ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Atualizar Meta'}
                                </Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                )}
            </AnimatePresence>
        </motion.div>
    );
}
